additions = {
    # Book 249 - Робинзон Крузо (оригиналы 215-276, нужно +430-480)
    (249,0): ' Историк Хуан Коул описал «колонизаторскую психологию»: европеец на пустом месте немедленно начинает воспроизводить цивилизацию. Крузо — архетип этой психологии. Он не отдыхает на острове — он строит Англию в миниатюре. Позже постколониальные критики увидят в этом не триумф человека — а идеологию контроля над природой и людьми. Но сам Дефо видел это иначе: труд как достоинство, создание как смысл. Эта двойственность делает роман интереснее любого одностороннего прочтения.',
    (249,1): ' Психолог Джеймс Пеннебейкер исследовал влияние письма на психику: люди которые ведут дневник в трудные периоды — лучше справляются со стрессом, яснее понимают происходящее, меньше впадают в панику. Дневник Крузо — интуитивная психотерапия. Он не просто записывает события — он структурирует хаос. Превращает непонятное в понятное, случайное в систему. Дефо написал первую книгу о ценности нарративной терапии — за 270 лет до того как психологи дали ей имя.',
    (249,2): ' Психолог Мартин Селигман исследовал посттравматический рост: некоторые люди после тяжёлого опыта становятся глубже, мудрее, устойчивее — не несмотря на него, а благодаря ему. Крузо — редкий пример. 28 лет одиночества не сломали его — они создали. Он вышел с острова другим человеком: более самостоятельным, более благодарным, более способным к самопознанию. Дефо показывает: человек не просто выживает — он растёт. Не всегда. Но возможность существует.',
    (249,3): ' Философ Хайдеггер описал «подручность»: вещи существуют для нас прежде всего как инструменты, и их ценность раскрывается в момент использования. Крузо понимает это инстинктивно: без инструментов невозможно не выжить — невозможно мыслить как цивилизованный человек. Инструменты — это не просто средства. Это возможность реализовать намерение, превратить мысль в действие. Дефо написал философию инструментальности за 200 лет до Хайдеггера.',
    (249,4): ' Антрополог Маршалл Салинс в «Экономике каменного века» показал: так называемые «примитивные» народы работают меньше часов чем «цивилизованные» — и имеют больше свободного времени. Пятница — не дикарь которого нужно спасти. Он человек из другой, но полноценной культуры. Когда Крузо начинает видеть в нём человека — это переломный момент не только романа, но и европейского мышления о «другом». Дефо делает первый шаг — очень маленький, но заметный.',
    (249,5): ' Философ Алан Уотс описал «принцип благодарности»: умение видеть ресурсы а не дефицит определяет качество жизни независимо от обстоятельств. Крузо на необитаемом острове имеет: жильё, еду, здоровье, свободу. Он не счастлив — но он стабилен. Это не позитивное мышление и не самообман. Это когнитивный инструмент: переключить внимание с того чего нет на то что есть. Таблица плюсов и минусов Крузо — рационализация этого инструмента.',
    (249,6): ' Философ Альберт Камю описал абсурдного героя как того кто находит смысл в самом акте создания — не в его цели. Сизиф счастлив потому что катит камень. Крузо счастлив потому что строит. Его цель — выжить и уплыть. Но смысл он находит в процессе: в каждой балке, каждом горшке, каждом посеянном зёрне. Труд без гарантии результата — это не бессмысленность. Это единственный доступный смысл. Дефо понял это через повествование.',
    (249,7): ' Литературовед Иэн Ватт в «Подъёме романа» показал: «Робинзон Крузо» создал жанр именно потому что изменил отношения между автором, героем и читателем. Дефо притворился что публикует дневник реального человека — и читатели верили. Это первый в истории «реалистический» нарратив: не аллегория, не сказка, не история великих — а обычный человек в конкретных обстоятельствах. Этот сдвиг изменил всю последующую литературу.',
    (249,8): ' Психолог Джон Качиоппо исследовал одиночество: оно повышает кортизол, нарушает сон, ускоряет когнитивное угасание. Но Крузо возвращается к цивилизации — и обнаруживает что она стала чужой. Он привык к тишине, к собственному ритму, к отсутствию социальных обязательств. Это не патология — это адаптация. Слишком глубокая. Возвращение как утрата — тема которую Дефо только наметил, а последующая литература развила.',
    (249,9): ' Философ Умберто Эко описал «открытый текст»: произведение которое предлагает множество интерпретаций, не настаивая на одной. «Робинзон Крузо» — открытый текст: его читают как гимн труду, как критику колониализма, как протестантскую аллегорию, как историю выживания. Ни одна интерпретация не исчерпывает. Именно это делает книгу живой через 300 лет — она больше любого прочтения.',

    # Book 250 - Путь паломника (оригиналы 217-271, нужно +430-480)
    (250,0): ' Историк Альберт Кук описал «метафору пути» как одну из самых древних человеческих моделей понимания жизни. Она встречается в «Одиссее», «Божественной комедии», «Дон Кихоте». Буньян использует её в её наиболее чистой форме: путешествие — это жизнь, каждое препятствие — испытание, каждый попутчик — выбор. Эта структура работает на любой религиозной и культурной основе потому что соответствует реальному опыту: жизнь — это движение от начала к концу через испытания.',
    (250,1): ' Психолог Мартин Селигман описал «выученную беспомощность»: состояние когда человек перестаёт верить что может повлиять на ситуацию. Болото Уныния — это психологическое состояние а не место. Сомнения которые топят — не новая информация. Они были и раньше. Просто в какой-то момент им дали слишком много веса. Буньян показывает: выход из болота — не исчезновение сомнений, а решение идти несмотря на них. Помощник Помощь появляется именно для того кто решает продолжать.',
    (250,2): ' Психолог Михай Чиксентмихайи исследовал творческий опыт в ограниченных условиях: многие великие произведения созданы в тюрьме, болезни, изгнании. Ограничение убирает отвлечение и заставляет сосредоточиться на главном. Буньян в тюрьме имел одну книгу — Библию. Из этой бедности он создал богатство. Поэтому «Путь паломника» такой плотный: каждый образ несёт максимальную нагрузку смысла. Ограничение как источник — это не утешение. Это наблюдение которое подтверждается снова и снова.',
    (250,3): ' Социолог Марк Грановеттер описал «силу слабых связей»: люди с разнообразными знакомствами получают больше возможностей чем те у кого только тесный круг. Но это про информацию. Для ценностного пути важна другая динамика: один человек который помогает двигаться вперёд стоит дороже десятка которые тянут назад. Буньян это понял: Христиане выбирают попутчиков осознанно. Это не снобизм — это самосохранение.',
    (250,4): ' Историк Кристофер Хилл в «Миром перевёрнутом вверх дном» описал Англию XVII века как общество на разломе: революция, война, религиозные конфликты. Ярмарка Тщеславия — реальное место в этой Англии. Буньян видел своими глазами как продаются принципы за должности, репутации за деньги, истины за безопасность. Его аллегория — документ эпохи. Она не устарела потому что описывает не XVII век — а механизм который воспроизводится в каждую эпоху.',
    (250,5): ' Психолог Отто Ранк описал «страх жизни»: парадоксальный страх реализации своего потенциала — потому что это означает ответственность и уязвимость. Груз грехов Христианина — это именно такой страх. Он несёт всё что делает его несвободным. Снятие груза не решает проблему немедленно — но освобождает ресурс для движения. Буньян показывает: первый шаг к свободе — не достижение цели, а освобождение от того что мешает идти.',
    (250,6): ' Философ Людвиг Витгенштейн писал: «Границы моего языка — это границы моего мира». Аллегория расширяет язык: она создаёт слова для опыта который трудно передать буквально. «Болото Уныния», «Ярмарка Тщеславия», «Небесный Град» — это не просто образы. Это концепции которые вошли в английский язык как обозначения реального опыта. Буньян расширил мир своих читателей — дав имена тому что они переживали но не умели назвать.',
    (250,7): ' Антрополог Клиффорд Гирц описал культуру как «паутину смыслов»: универсальное всегда выражается через конкретное. Буньян написал предельно конкретно — о конкретном Христианине из конкретной страны в конкретный период. И именно поэтому его поняли 200 культур. Конкретность — не ограничение. Это способ достучаться до универсального через частное.',
    (250,8): ' Философ Виктор Франкл писал: «Те кто знает «зачем» — переносят почти любое «как»». Небесный Град Буньяна — это зачем которое делает возможным весь путь. Цель не обязана быть материальной или немедленно достижимой. Её функция — создавать направление и смысл движения. Это работает для религиозного и нерелигиозного читателя одинаково: жизнь с ясной целью — качественно иная жизнь.',
    (250,9): ' Историк письменности Джек Гуди показал: доступность простого языка в тексте — это политическое решение. Элиты контролировали знание через сложность языка. Буньян писал для тех кого эти элиты исключали. Его простота — не упрощение. Это демократизация смысла. Именно поэтому «Путь паломника» стал одной из самых читаемых книг в истории: он пришёл туда где его ждали.',

    # Book 253 - Маленькие женщины (оригиналы 343-439, нужно +270-360)
    (253,0): ' Психолог Рик Хансон описал «нейронную пластичность достаточности»: люди которые регулярно замечают что у них есть достаточно — меняют нейронные паттерны тревоги и дефицита. Семья Марч живёт эту практику не как идеологию — как ежедневный выбор. Олкотт описала это задолго до нейронауки: бедность с достоинством возможна — и не требует особого характера. Только особого внимания к тому что есть.',
    (253,1): ' Психолог Сандра Бем описала «психологическую андрогинность»: здоровая личность сочетает качества которые культура называет «мужскими» и «женскими». Мэг чуткая и практичная, Джо смелая и нежная, Бет тихая и сильная, Эми амбициозная и заботливая. Олкотт не навязывает моделей — она показывает что идентичность богаче любых категорий. Четыре сестры из одного дома — четыре доказательства.',
    (253,2): ' Историк Линда Хёрш описала Луизу Мэй Олкотт как первую американскую женщину-автора которая писала о женском опыте от первого лица — без мужского псевдонима и без извинений. Джо — автобиографический персонаж. Выбор себя который делает Джо — это выбор который делала Олкотт каждый день когда садилась писать вместо того чтобы выйти замуж. Роман не просто описывает этот выбор. Он его легитимизирует.',
    (253,3): ' Психолог Элизабет Кюблер-Росс описала стадии горя: отрицание, злость, торг, депрессия, принятие. Смерть Бет проводит через них всю семью — и читателя. Олкотт не защищает читателя от потери: она позволяет её прожить в безопасном пространстве текста. Именно поэтому читатели плачут над Бет — и не стесняются. Книга создала место где это нормально.',
    (253,4): ' Философ Ролз описал справедливость как то что выбирают за «завесой неведения»: не зная будешь ли ты богатым или бедным. По этому стандарту выбор Мэг — справедлив: она берёт человека а не статус. Олкотт не романтизирует бедность. Она исследует что происходит когда люди выбирают друг друга — и затем строят жизнь вместе с её настоящими трудностями. Это честнее большинства любовных историй.',
    (253,5): ' Нейробиолог Наом Хомский описал язык как врождённую способность — но творческое письмо требует большего: соединить врождённое с выученным и пережитым. Джо пишет потому что иначе не может. Это не метафора — это нейробиологическая реальность для некоторых людей: создание текста — способ обработки реальности. Уничтожение рукописи — акт насилия над собой. Олкотт описала это через Джо — потому что пережила сама.',
    (253,6): ' Психолог Джон Готтман описал «метакоммуникацию»: разговор о том как мы разговариваем — признак зрелых отношений. Марми мастер метакоммуникации: она не только решает конфликты — она обсуждает с детьми как они общаются. Это работает не потому что Марми идеальна. А потому что она последовательна и присутствует. Её главный инструмент — внимание. Самое редкое что могут дать родители.',
    (253,7): ' Историк Барбара Уэлтер описала «культ истинной женственности»: XIX век требовал от женщин благочестия, чистоты, покорности и домашности. Джо нарушает все четыре пункта. Олкотт показывает: клетка реальна — но в ней можно бунтовать. Не без цены. Но можно. Именно это послание сделало книгу важной для поколений читательниц которые чувствовали ту же клетку.',
    (253,8): ' Психолог Джеймс Марсия описал «достижение идентичности»: фазу когда человек прошёл через кризис и сделал осознанный выбор. Девочки Марч проходят через кризисы — и выходят с более чёткими идентичностями. Олкотт не романтизирует трудности. Она показывает механизм: испытание как инструмент роста. Не всегда. Но при наличии поддержки — часто.',
    (253,9): ' Социолог Роберт Патнэм описал «социальный капитал»: ценность связей и доверия внутри сообщества. Семья Марч и Лоренсы — живая модель высокого социального капитала: они доверяют, помогают, создают вместе. Олкотт показывает что это не случайность. Это результат постоянных инвестиций времени и внимания. Дружба строится годами — и это главное что делает роман тёплым спустя 150 лет.',
}

for book in data:
    bid = book['id']
    for i, t in enumerate(book['thoughts']):
        if (bid, i) in additions:
            t['example'] = t['example'] + additions[(bid, i)]

with open('/root/books/webapp/books.json', 'w') as f:
    json.dump(data, f, ensure_ascii=False)

# Verify + trim > 820
ids = [249, 250, 253]
changed = False
for book in data:
    if book['id'] not in ids:
        continue
    for t in book['thoughts']:
        ex = t['example']
        if len(ex) > 820:
            pos = ex[:815].rfind('.')
            if pos > 700:
                t['example'] = ex[:pos+1]
                changed = True

if changed:
    with open('/root/books/webapp/books.json', 'w') as f:
        json.dump(data, f, ensure_ascii=False)

for book in data:
    if book['id'] in ids:
        lens = [len(t['example']) for t in book['thoughts']]
        bad = [(i, l) for i, l in enumerate(lens) if l < 700 or l > 820]
        status = 'OK' if not bad else f'BAD={bad}'
        print(f'ID={book["id"]} {book["title"][:22]}: min={min(lens)} max={max(lens)} {status}')
